```cpp
// Download function for assets with progress callback
bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Downloading new version of assets from %s", url.c_str());

    // Cancel current memory mapping of asset partition
    if (mmap_handle_ != 0)
    {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }
    checksum_valid_ = false;
    assets_.clear();

    // Download new asset file
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return false;
    }

    if (http->GetStatusCode() != 200)
    {
        ESP_LOGE(TAG, "Failed to get assets, status code: %d", http->GetStatusCode());
        return false;
    }

    size_t content_length = http->GetBodyLength();
    if (content_length == 0)
    {
        ESP_LOGE(TAG, "Failed to get content length");
        return false;
    }

    if (content_length > partition_->size)
    {
        ESP_LOGE(TAG, "Assets file size (%u) is larger than partition size (%lu)", content_length, partition_->size);
        return false;
    }

    // Define sector size as 4KB (standard sector size for ESP32)
    const size_t SECTOR_SIZE = esp_partition_get_main_flash_sector_size();

    // Calculate number of sectors to erase
    size_t sectors_to_erase = (content_length + SECTOR_SIZE - 1) / SECTOR_SIZE; // Round up
    size_t total_erase_size = sectors_to_erase * SECTOR_SIZE;

    ESP_LOGI(TAG, "Sector size: %u, content length: %u, sectors to erase: %u, total erase size: %u",
             SECTOR_SIZE, content_length, sectors_to_erase, total_erase_size);

    // Write new asset file to partition, erase and write in chunks
    char buffer[512];
    size_t total_written = 0;
    size_t recent_written = 0;
    size_t current_sector = 0;
    auto last_calc_time = esp_timer_get_time();

    while (true)
    {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret < 0)
        {
            ESP_LOGE(TAG, "Failed to read HTTP data: %s", esp_err_to_name(ret));
            return false;
        }

        if (ret == 0)
        {
            break;
        }

        // Check if we need to erase new sectors
        size_t write_end_offset = total_written + ret;
        size_t needed_sectors = (write_end_offset + SECTOR_SIZE - 1) / SECTOR_SIZE;

        // Erase necessary sectors
        while (current_sector < needed_sectors)
        {
            size_t sector_start = current_sector * SECTOR_SIZE;
            size_t sector_end = (current_sector + 1) * SECTOR_SIZE;

            // Ensure erase range doesn't exceed partition size
            if (sector_end > partition_->size)
            {
                ESP_LOGE(TAG, "Sector end (%u) exceeds partition size (%lu)", sector_end, partition_->size);
                return false;
            }

            ESP_LOGD(TAG, "Erasing sector %u (offset: %u, size: %u)", current_sector, sector_start, SECTOR_SIZE);
            esp_err_t err = esp_partition_erase_range(partition_, sector_start, SECTOR_SIZE);
            if (err != ESP_OK)
            {
                ESP_LOGE(TAG, "Failed to erase sector %u at offset %u: %s", current_sector, sector_start, esp_err_to_name(err));
                return false;
            }

            current_sector++;
        }

        // Write data to partition
        esp_err_t err = esp_partition_write(partition_, total_written, buffer, ret);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to write to assets partition at offset %u: %s", total_written, esp_err_to_name(err));
            return false;
        }

        total_written += ret;
        recent_written += ret;

        // Calculate progress and speed
        if (esp_timer_get_time() - last_calc_time >= 1000000 || total_written == content_length || ret == 0)
        {
            size_t progress = total_written * 100 / content_length;
            size_t speed = recent_written; // Bytes per second
            ESP_LOGI(TAG, "Progress: %u%% (%u/%u), Speed: %u B/s, Sectors erased: %u",
                     progress, total_written, content_length, speed, current_sector);
            if (progress_callback)
            {
                progress_callback(progress, speed);
            }
            last_calc_time = esp_timer_get_time();
            recent_written = 0; // Reset recent written bytes
        }
    }

    http->Close();

    if (total_written != content_length)
    {
        ESP_LOGE(TAG, "Downloaded size (%u) does not match expected size (%u)", total_written, content_length);
        return false;
    }

    ESP_LOGI(TAG, "Assets download completed, total written: %u bytes, total sectors erased: %u",
             total_written, current_sector);

    // Re-initialize asset partition
    if (!InitializePartition())
    {
        ESP_LOGE(TAG, "Failed to re-initialize assets partition");
        return false;
    }

    return true;
}
