// Example of initializing partition mapping using esp_partition_mmap
bool Assets::InitializePartition()
{
    // Find the partition named "assets"
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Validate the partition data structure (example check)
    if (mmap_root_[0] != 'A' || mmap_root_[1] != 'S')
    {
        ESP_LOGE(TAG, "Invalid assets partition header");
        return false;
    }

    // Set flags indicating valid state
    partition_valid_ = true;
    checksum_valid_ = true;

    return true;
}
```

