// Example of parsing asset table from mapped memory
void Assets::ParseAssetTable()
{
    const mmap_assets_table* asset_table = reinterpret_cast<const mmap_assets_table*>(mmap_root_ + sizeof(uint32_t));

    // Assuming we know how many entries are in the table
    uint32_t entry_count = *reinterpret_cast<const uint32_t*>(mmap_root_);

    for (uint32_t i = 0; i < entry_count; ++i)
    {
        const mmap_assets_table& entry = asset_table[i];
        Asset asset;
        asset.size = entry.asset_size;
        asset.offset = entry.asset_offset;

        assets_[std::string(entry.asset_name)] = asset;
    }
}
