// Example of how to use HTTP client for downloading with progress callback
bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    // Use Http class or similar HTTP client
    auto http = std::make_unique<Http>();
    if (!http->Connect(url)) {
        ESP_LOGE(TAG, "Failed to connect to %s", url.c_str());
        return false;
    }

    // Simulate download with progress updates
    size_t total_size = http->GetContentLength();
    size_t downloaded = 0;
    std::vector<uint8_t> buffer(1024);
    auto start_time = esp_timer_get_time();

    while (downloaded < total_size) {
        size_t bytes_read = http->Read(buffer.data(), buffer.size());
        if (bytes_read <= 0) break;

        downloaded += bytes_read;
        int progress = (int)((downloaded * 100) / total_size);

        // Calculate speed
        auto current_time = esp_timer_get_time();
        double elapsed_seconds = (current_time - start_time) / 1000000.0;
        size_t speed = (elapsed_seconds > 0) ? (downloaded / elapsed_seconds) : 0;

        if (progress_callback) {
            progress_callback(progress, speed);
        }
    }

    // Save downloaded content to flash partition
    // ... implementation depends on specific requirements ...

    return true;
}
