// Example of how to write to flash partition (similar to existing InitializePartition logic)
bool WriteToFlashPartition(const uint8_t* data, size_t size, uint32_t offset)
{
    // Get partition handle
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_NVS, "assets");

    if (!partition) {
        ESP_LOGE(TAG, "No assets partition found");
        return false;
    }

    // Erase sector before writing
    esp_err_t err = esp_partition_erase_range(partition, offset, size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        return false;
    }

    // Write data to partition
    err = esp_partition_write(partition, offset, data, size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
        return false;
    }

    return true;
}
