bool CompareVersions(const std::vector<int>& current, const std::vector<int>& newVer) {
    size_t minSize = std::min(current.size(), newVer.size());

    for (size_t i = 0; i < minSize; ++i) {
        if (current[i] < newVer[i]) return true;
        if (current[i] > newVer[i]) return false;
    }

    // If all compared parts are equal, longer version is newer
    return newVer.size() > current.size();
}
