    }

    if (rx_handle_ == nullptr || !input_enabled_) {
        ESP_LOGW(TAG, "I2S receive handle not initialized or input disabled");
        return false;
    }

    size_t bytes_read = 0;
    esp_err_t result = i2s_channel_read(rx_handle_, data.data(), data.size() * sizeof(int16_t), &bytes_read, portMAX_DELAY);

    if (result != ESP_OK) {
