int Es8388AudioCodec::Read(int16_t *dest, int samples)
{
    if (!input_enabled_ || !input_dev_ || dest == nullptr) {
        return 0;
    }

    size_t bytes_to_read = samples * sizeof(int16_t);
    size_t bytes_read = 0;

    esp_err_t ret = esp_codec_dev_read(input_dev_, dest, bytes_to_read, &bytes_read, portMAX_DELAY);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read audio data: %s", esp_err_to_name(ret));
        return -1;
    }

    return bytes_read / sizeof(int16_t); // Return number of samples read
}
