void SetOutputState(uint8_t bit, uint8_t level)
{
    uint8_t reg = (bit < 8) ? 0x02 : 0x03;  // Output register for port 0 or 1
    uint8_t mask = 1 << (bit % 8);

    uint8_t current_value = ReadReg(reg);
    if (level) {
        current_value |= mask;
    } else {
        current_value &= ~mask;
    }
    WriteReg(reg, current_value);
}
