// I2C device base class pattern used in XL9555
class I2cDevice {
protected:
    i2c_master_bus_handle_t i2c_bus_;
    uint8_t addr_;

public:
    I2cDevice(i2c_master_bus_handle_t bus, uint8_t address) 
        : i2c_bus_(bus), addr_(address) {}

    void WriteReg(uint8_t reg, uint8_t value) {
        i2c_cmd_handle_t cmd = i2c_cmd_link_create();
        i2c_master_start(cmd);
        i2c_master_write_byte(cmd, (addr_ << 1) | I2C_MASTER_WRITE, true);
        i2c_master_write_byte(cmd, reg, true);
        i2c_master_write_byte(cmd, value, true);
        i2c_master_stop(cmd);
        i2c_master_cmd_begin(i2c_bus_, cmd, 1000 / portTICK_PERIOD_MS);
        i2c_cmd_link_delete(cmd);
    }

    uint8_t ReadReg(uint8_t reg) {
        uint8_t value;
        i2c_cmd_handle_t cmd = i2c_cmd_link_create();
        i2c_master_start(cmd);
        i2c_master_write_byte(cmd, (addr_ << 1) | I2C_MASTER_WRITE, true);
        i2c_master_write_byte(cmd, reg, true);
        i2c_master_stop(cmd);
        i2c_master_cmd_begin(i2c_bus_, cmd, 1000 / portTICK_PERIOD_MS);
        i2c_cmd_link_delete(cmd);

        cmd = i2c_cmd_link_create();
        i2c_master_start(cmd);
        i2c_master_write_byte(cmd, (addr_ << 1) | I2C_MASTER_READ, true);
        i2c_master_read_byte(cmd, &value, I2C_MASTER_LAST_NACK);
        i2c_master_stop(cmd);
        i2c_master_cmd_begin(i2c_bus_, cmd, 1000 / portTICK_PERIOD_MS);
        i2c_cmd_link_delete(cmd);
        return value;
    }
};
