// Convert bits to bytes by grouping 8 bits into a byte
std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    std::vector<uint8_t> bytes;
    bytes.reserve((bits.size() + 7) / 8); // Reserve space for efficiency

    uint8_t byte = 0;
    size_t bit_count = 0;

    for (uint8_t bit : bits)
    {
        byte |= (bit << (7 - bit_count)); // Pack bits from MSB to LSB
        bit_count++;

        if (bit_count == 8)
        {
            bytes.push_back(byte);
            byte = 0;
            bit_count = 0;
        }
    }

    // Handle remaining bits (pad with zeros if necessary)
    if (bit_count > 0)
    {
        bytes.push_back(byte);
    }

    return bytes;
}
