// Example of sending audio data via UDP (similar pattern to what's needed)
bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (!IsAudioChannelOpened()) {
        ESP_LOGW(TAG, "Audio channel is not opened");
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Prepare audio packet header and payload
    uint8_t type = 0x01;  // Audio packet type
    uint8_t flags = 0x00; // Flags
    uint16_t payload_len = packet->payload.size();
    uint32_t ssrc = 0x12345678; // Dummy SSRC
    uint32_t timestamp = packet->timestamp;
    uint32_t sequence = local_sequence_++;

    // Construct packet buffer
    std::vector<uint8_t> buffer(sizeof(type) + sizeof(flags) + sizeof(payload_len) + 
                                sizeof(ssrc) + sizeof(timestamp) + sizeof(sequence) + payload_len);

    size_t offset = 0;
    memcpy(buffer.data() + offset, &type, sizeof(type)); offset += sizeof(type);
    memcpy(buffer.data() + offset, &flags, sizeof(flags)); offset += sizeof(flags);
    memcpy(buffer.data() + offset, &payload_len, sizeof(payload_len)); offset += sizeof(payload_len);
    memcpy(buffer.data() + offset, &ssrc, sizeof(ssrc)); offset += sizeof(ssrc);
    memcpy(buffer.data() + offset, &timestamp, sizeof(timestamp)); offset += sizeof(timestamp);
    memcpy(buffer.data() + offset, &sequence, sizeof(sequence)); offset += sizeof(sequence);
    memcpy(buffer.data() + offset, packet->payload.data(), payload_len);

    // Send over UDP
    if (!udp_->Send((const char*)buffer.data(), buffer.size())) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        return false;
    }

    return true;
}
