bool MqttProtocol::OpenAudioChannel()
{
    if (udp_ != nullptr)
    {
        ESP_LOGW(TAG, "Audio channel already opened");
        return true;
    }

    // Wait for server hello message to be received
    if (xEventGroupWaitBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT,
                            pdFALSE, pdTRUE, pdMS_TO_TICKS(5000)) == 0)
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello");
        return false;
    }

    // Create UDP socket
    auto network = Board::GetInstance().GetNetwork();
    udp_ = network->CreateUdp();

    // Connect to UDP server
    if (!udp_->Connect(udp_server_, udp_port_))
    {
        ESP_LOGE(TAG, "Failed to connect to UDP server");
        udp_.reset();
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}
