bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    // Prepare binary protocol based on version
    if (version_ == 2) 
    {
        BinaryProtocol2 bp2{};
        bp2.version = htons(2);
        bp2.type = htons(0); // OPUS type
        bp2.timestamp = htonl(packet->timestamp);
        bp2.payload_size = htonl(packet->payload.size());

        // Copy payload into buffer
        std::vector<uint8_t> buffer(sizeof(BinaryProtocol2) + packet->payload.size());
        memcpy(buffer.data(), &bp2, sizeof(BinaryProtocol2));
        memcpy(buffer.data() + sizeof(BinaryProtocol2), packet->payload.data(), packet->payload.size());

        if (!websocket_->Send(buffer.data(), buffer.size(), true))
        {
            ESP_LOGE(TAG, "Failed to send audio packet");
            SetError(Lang::Strings::SERVER_ERROR);
            return false;
        }
    }
    else if (version_ == 3)
    {
        BinaryProtocol3 bp3{};
        bp3.type = 0; // OPUS type
        bp3.reserved = 0;
        bp3.payload_size = htons(packet->payload.size());

        std::vector<uint8_t> buffer(sizeof(BinaryProtocol3) + packet->payload.size());
        memcpy(buffer.data(), &bp3, sizeof(BinaryProtocol3));
        memcpy(buffer.data() + sizeof(BinaryProtocol3), packet->payload.data(), packet->payload.size());

        if (!websocket_->Send(buffer.data(), buffer.size(), true))
        {
            ESP_LOGE(TAG, "Failed to send audio packet");
            SetError(Lang::Strings::SERVER_ERROR);
            return false;
        }
    }
    else
    {
        // Default version (v1): send raw payload directly
        if (!websocket_->Send(packet->payload.data(), packet->payload.size(), true))
        {
            ESP_LOGE(TAG, "Failed to send audio packet");
